// Extrai dados do payload da Evolution API
const body = $input.first().json.body || $input.first().json;

// Evolution API payload structure
const event = body.event || '';
const instanceName = body.instance || '';

// Ignora eventos que não são mensagens recebidas
if (event !== 'messages.upsert') {
  return [{ json: { ignore: true } }];
}

const data = body.data || {};
const key = data.key || {};

// Ignora mensagens enviadas pelo próprio bot
if (key.fromMe === true) {
  return [{ json: { ignore: true } }];
}

// Extrai número do remetente (remove @s.whatsapp.net)
const remoteJid = key.remoteJid || '';
const fromNumber = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

// Extrai texto da mensagem
const message = data.message || {};
const messageText = message.conversation 
  || message.extendedTextMessage?.text 
  || message.buttonsResponseMessage?.selectedDisplayText
  || message.listResponseMessage?.singleSelectReply?.selectedRowId
  || '';

const pushName = data.pushName || '';
const messageTimestamp = data.messageTimestamp || Math.floor(Date.now() / 1000);

return [{
  json: {
    ignore: false,
    instanceName,
    fromNumber,
    messageText: messageText.trim(),
    pushName,
    messageTimestamp,
    rawEvent: event
  }
}];

// Merge dados extraídos da mensagem com dados da clínica
const msgData = $('Extrair dados da mensagem').first().json;
const clinicData = $('Buscar clínica por instância').first().json;

return [{
  json: {
    // Dados da mensagem
    fromNumber: msgData.fromNumber,
    messageText: msgData.messageText,
    pushName: msgData.pushName,
    instanceName: msgData.instanceName,
    messageTimestamp: msgData.messageTimestamp,
    // Dados da clínica
    clinic_id: clinicData.id,
    clinic_name: clinicData.name,
    clinic_whatsapp: clinicData.whatsapp_number,
    clinic_address: clinicData.address,
    clinic_hours: clinicData.business_hours,
    clinic_insurances: clinicData.accepted_insurances,
    bot_prompt: clinicData.bot_prompt,
    human_agent_number: clinicData.human_agent_number
  }
}];

// Paciente NÃO encontrado — criar conversa com estado IDENTIFICATION_ASK
const ctx = $('Montar contexto').first().json;

return [{
  json: {
    ...ctx,
    patient_id: null,
    patient_name: ctx.pushName || 'paciente',
    conversation_state: 'IDENTIFICATION_ASK'
  }
}];

// Paciente encontrado — merge dados do paciente com contexto
const ctx = $('Montar contexto').first().json;
const patient = $('Buscar paciente').first().json;

return [{
  json: {
    ...ctx,
    patient_id: patient.id,
    patient_name: patient.name || ctx.pushName || 'paciente',
    patient_insurance: patient.insurance,
    patient_cpf_last4: patient.cpf_last4,
    patient_birth_date: patient.birth_date
  }
}];

// Merge conversa com contexto completo
const ctx = $('Merge dados paciente').first().json;
const conv = $('Carregar/criar conversa').first().json;
const msgData = $('Extrair dados da mensagem').first().json;

// Append mensagem recebida ao histórico
let messages = [];
try {
  messages = typeof conv.messages === 'string' ? JSON.parse(conv.messages) : (conv.messages || []);
} catch(e) {
  messages = [];
}

messages.push({
  role: 'user',
  content: msgData.messageText,
  timestamp: new Date().toISOString()
});

return [{
  json: {
    ...ctx,
    conversation_id: conv.id,
    conversation_state: conv.state || 'MENU',
    messages: messages,
    messageText: msgData.messageText
  }
}];

// Estado MENU: processa escolha do paciente ou exibe menu
const data = $input.first().json;
const choice = data.messageText.trim();

let responseText = '';
let newState = 'MENU';

switch(choice) {
  case '1':
    newState = 'SCHEDULING_SPECIALTY';
    responseText = '__TRIGGER_SCHEDULING__';
    break;
  case '2':
    newState = 'CANCELLATION_SELECT';
    responseText = '__TRIGGER_CANCELLATION__';
    break;
  case '3':
    newState = 'DOUBT';
    responseText = '__TRIGGER_DOUBT__';
    break;
  case '4':
    newState = 'MENU';
    responseText = '__TRIGGER_PRICES__';
    break;
  default:
    // Exibe menu principal
    responseText = `Olá, ${data.patient_name}! 👋\nSou a assistente virtual da ${data.clinic_name}.\n\nComo posso ajudar?\n\n1️⃣ Agendar consulta\n2️⃣ Cancelar ou remarcar consulta\n3️⃣ Tirar dúvidas\n4️⃣ Consultar valores\n\nDigite o número da opção desejada.`;
    newState = 'MENU';
    break;
}

return [{
  json: {
    ...data,
    responseText,
    newState,
    triggerSubflow: ['1','2','3','4'].includes(choice) ? choice : null
  }
}];

// Restaura contexto completo após Postgres UPDATE (que apaga $json)
const ctx = $('Preparar contexto completo').first().json;
const menu = $('Processar menu').first().json;
return [{ json: { ...ctx, triggerSubflow: menu.triggerSubflow, newState: menu.newState } }];

