const ctx = $('Preparar novo contato').first().json;
const conv = $input.first().json;
const hasConversation = !!(conv && conv.id);

let messages = [];
if (hasConversation && conv.messages) {
  try {
    messages = typeof conv.messages === 'string' ? JSON.parse(conv.messages) : conv.messages;
  } catch(e) { messages = []; }
}

return [{
  json: {
    ...ctx,
    conversation_id: hasConversation ? conv.id : null,
    conversation_state: hasConversation ? conv.state : 'IDENTIFICATION_ASK',
    messages,
    isFirstContact: !hasConversation
  }
}];

const data = $input.first().json;
const parts = data.messageText.trim().split(/\s+/);
const command = parts[0].toLowerCase();
const targetNumber = (parts[1] || '').replace(/\D/g, '');

return [{ json: { ...data, command, targetNumber } }];

const ctx = $('Restaurar contexto para sub-fluxo').first().json;
const doctors = $input.all().map(d => d.json).filter(d => d.name);

let text = '💰 *Valores das consultas:*\n\n';

if (doctors.length === 0) {
  text += 'Informação não disponível no momento.';
} else {
  let currentSpecialty = '';
  for (const d of doctors) {
    if (d.specialty !== currentSpecialty) {
      currentSpecialty = d.specialty;
      text += `*${currentSpecialty}*\n`;
    }
    const price = d.consultation_price
      ? `R$ ${Number(d.consultation_price).toFixed(2).replace('.', ',')}`
      : 'Sob consulta';
    text += `  • ${d.name} — ${price}\n`;
  }
}

text += '\nConvênios aceitos: ' + (Array.isArray(ctx.clinic_insurances) ? ctx.clinic_insurances.join(', ') : 'Particular');
text += '\n\nDeseja agendar uma consulta? Digite *1*.';
text += '\n\n1️⃣ Agendar consulta\n2️⃣ Cancelar ou remarcar\n3️⃣ Tirar dúvidas\n4️⃣ Consultar valores';

return [{ json: { ...ctx, priceText: text } }];
